def least_frequent_word(s):
    word_freq = {}
    for word in s.split():
        word = word.lower()
        if word not in word_freq:
            word_freq[word] = 1
        else:
            word_freq[word] += 1

    min_count, min_word = float('inf'), ''
    for word, count in word_freq.items():
        if count < min_count:
            min_count, min_word = count, word
    return min_word
